import{_ as e,o,c as i,a2 as l}from"./chunks/framework.QoSTM79V.js";const h=JSON.parse('{"title":"Mango 后端架构边界收敛总文档","description":"","frontmatter":{},"headers":[],"relativePath":"mango-docs/mango-backend-architecture-boundary-refactor-master-plan.md","filePath":"mango-docs/mango-backend-architecture-boundary-refactor-master-plan.md"}'),n={name:"mango-docs/mango-backend-architecture-boundary-refactor-master-plan.md"};function d(c,a,t,s,r,p){return o(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="mango-后端架构边界收敛总文档" tabindex="-1">Mango 后端架构边界收敛总文档 <a class="header-anchor" href="#mango-后端架构边界收敛总文档" aria-label="Permalink to &quot;Mango 后端架构边界收敛总文档&quot;">​</a></h1><ul><li>创建日期：2026-04-14</li><li>状态：进行中</li><li>类型：总目标文档</li></ul><hr><h2 id="_1-文档定位" tabindex="-1">1. 文档定位 <a class="header-anchor" href="#_1-文档定位" aria-label="Permalink to &quot;1. 文档定位&quot;">​</a></h2><p>本文件不是 Sprint，不直接作为开发交付物验收。</p><p>本文件用于回答三个问题：</p><ol><li>Mango 后端为了达成最终目标，当前还存在哪些架构缺陷</li><li>后端重构的总目标是什么</li><li>后续应拆成哪些可独立交付的子阶段 / Phase</li></ol><hr><h2 id="_2-最终目标" tabindex="-1">2. 最终目标 <a class="header-anchor" href="#_2-最终目标" aria-label="Permalink to &quot;2. 最终目标&quot;">​</a></h2><p>Mango 后端的最终目标不是“目录看起来分层”，而是形成一套真正适合 AI Agent 持续开发的后端底座。</p><p>目标状态如下：</p><ul><li>采用 <strong>模块化单体优先、远程化兼容保留</strong> 的架构</li><li>通过 <code>api/core/starter/starter-remote</code> 提供稳定模块边界</li><li><code>starter</code> 只负责装配，不承载长期业务语义</li><li><code>app</code> 负责部署装配与运行配置</li><li><code>common</code> 只保留稳定、低耦合、跨模块公共契约</li><li><code>infra</code> 只提供技术能力，不依赖平台业务模型</li><li><code>infra</code> 的客户端实时通信能力统一由 <code>mango-infra-realtime</code> 承担，旧 <code>mango-infra-sse</code> / <code>mango-infra-websocket</code> 不再作为独立上层依赖入口</li><li><code>platform</code> 模块按 bounded context 拆分，不再形成“平台杂项大模块”</li><li>文档、POM、目录、代码中的领域命名保持一致</li></ul><hr><h2 id="_3-当前主要问题" tabindex="-1">3. 当前主要问题 <a class="header-anchor" href="#_3-当前主要问题" aria-label="Permalink to &quot;3. 当前主要问题&quot;">​</a></h2><h3 id="_3-1-公共层过重" tabindex="-1">3.1 公共层过重 <a class="header-anchor" href="#_3-1-公共层过重" aria-label="Permalink to &quot;3.1 公共层过重&quot;">​</a></h3><p><code>mango-common</code> 当前同时承载：</p><ul><li>公共异常</li><li>统一返回模型</li><li>分页模型</li><li>校验注解</li><li>JSON 工具</li><li>Base64 工具</li><li>TokenContext 兼容类</li><li>日志语义注解</li></ul><p>风险：</p><ul><li>成为全局耦合源</li><li>新增代码天然往 <code>common</code> 里堆</li><li>AI Agent 无法稳定判断“什么该放 common、什么不该放”</li></ul><h3 id="_3-2-基础设施层反向感知业务层" tabindex="-1">3.2 基础设施层反向感知业务层 <a class="header-anchor" href="#_3-2-基础设施层反向感知业务层" aria-label="Permalink to &quot;3.2 基础设施层反向感知业务层&quot;">​</a></h3><p>示例：</p><ul><li><code>mango-infra-web</code> 依赖 <code>mango-authorization-api</code></li></ul><p>风险：</p><ul><li>infra 不再是通用底座</li><li>任何平台业务变动都可能反向污染基础设施层</li></ul><h3 id="_3-3-平台重模块职责膨胀" tabindex="-1">3.3 平台重模块职责膨胀 <a class="header-anchor" href="#_3-3-平台重模块职责膨胀" aria-label="Permalink to &quot;3.3 平台重模块职责膨胀&quot;">​</a></h3><p>重点模块：</p><ul><li><code>mango-identity</code></li><li><code>mango-authorization</code></li><li><code>mango-security</code></li><li><code>mango-system</code></li><li><code>mango-auth</code></li></ul><p>风险：</p><ul><li><code>mango-authorization</code> 曾混入身份事实，现已抽离到 <code>mango-identity</code></li><li><code>mango-security</code> 仅作为安全聚合入口，不承载认证、身份、授权业务事实</li><li><code>mango-system</code> 演变为配置/租户/字典/日志/路由的杂项箱</li><li><code>mango-auth</code> 同时承担认证与安全治理</li></ul><h3 id="_3-4-领域事实源不一致" tabindex="-1">3.4 领域事实源不一致 <a class="header-anchor" href="#_3-4-领域事实源不一致" aria-label="Permalink to &quot;3.4 领域事实源不一致&quot;">​</a></h3><p>表现：</p><ul><li>历史 Sprint 文档中保留过 <code>mango-user</code> / <code>mango-permission</code> 旧叙述</li><li>当前有效模块以源码目录和聚合 POM 为准：身份事实归入 <code>mango-identity</code>，授权事实归入 <code>mango-authorization</code></li><li>当前有效 README、索引和架构文档不得再把 <code>mango-user</code> / <code>mango-permission</code> 当作有效模块</li></ul><p>风险：</p><ul><li>AI 生成代码时会错误引用模块</li><li>Review 与实现基线不一致</li></ul><hr><h2 id="_4-总体收敛原则" tabindex="-1">4. 总体收敛原则 <a class="header-anchor" href="#_4-总体收敛原则" aria-label="Permalink to &quot;4. 总体收敛原则&quot;">​</a></h2><h3 id="_4-1-分层依赖" tabindex="-1">4.1 分层依赖 <a class="header-anchor" href="#_4-1-分层依赖" aria-label="Permalink to &quot;4.1 分层依赖&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app -&gt; starter/adapter -&gt; core -&gt; api -&gt; common-kernel</span></span></code></pre></div><h3 id="_4-2-职责边界" tabindex="-1">4.2 职责边界 <a class="header-anchor" href="#_4-2-职责边界" aria-label="Permalink to &quot;4.2 职责边界&quot;">​</a></h3><ul><li><code>common</code>: 公共内核与契约</li><li><code>infra</code>: 技术能力</li><li><code>platform</code>: 通用业务域</li><li><code>app</code>: 部署装配</li></ul><h3 id="_4-3-当前重构顺序" tabindex="-1">4.3 当前重构顺序 <a class="header-anchor" href="#_4-3-当前重构顺序" aria-label="Permalink to &quot;4.3 当前重构顺序&quot;">​</a></h3><p>原文档曾按 Sprint 09-12 规划为：</p><ol><li><code>mango-common</code></li><li><code>mango-infra-web</code> / <code>mango-infra-security</code></li><li><code>mango-infra-kv</code></li><li><code>mango-authorization</code></li><li><code>mango-system</code></li><li><code>mango-auth</code></li><li><code>mango-admin-app</code></li></ol><p>但实际执行中，阶段 3 没有继续沿用旧 Sprint 顺序，而是先完成了 <code>mango-infra-realtime</code>，将旧 <code>mango-infra-sse</code> 与 <code>mango-infra-websocket</code> 收敛为统一 server-client realtime 能力。该调整是合理的，因为 realtime 是 infra 层协议能力收口，且会影响 <code>mango-biz-notification</code>、<code>mango-admin-app</code> 和后续平台模块的实时投递接入方式。</p><p>因此，自 2026-04-19 起，本文档以 <code>2026-04-17-backend-module-by-module-refactor-plan.md</code> 的 Phase 主链路为准，重构顺序调整为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Phase -1 模块归属决策门</span></span>\n<span class="line"><span>  -&gt; Phase 0 事实源校准</span></span>\n<span class="line"><span>  -&gt; Phase 1 mango-common</span></span>\n<span class="line"><span>  -&gt; Phase 2 mango-infra-kv</span></span>\n<span class="line"><span>  -&gt; Phase 3 mango-infra-realtime</span></span>\n<span class="line"><span>  -&gt; Phase 4 mango-infra-security + mango-infra-web</span></span>\n<span class="line"><span>  -&gt; Phase 5 mango-gateway</span></span>\n<span class="line"><span>  -&gt; Phase 6 mango-authorization</span></span>\n<span class="line"><span>  -&gt; Phase 7 mango-system</span></span>\n<span class="line"><span>  -&gt; Phase 8 mango-auth</span></span>\n<span class="line"><span>  -&gt; Phase 9 mango-admin-app</span></span>\n<span class="line"><span>  -&gt; Phase 10 平台非主链路模块标准化（按需）</span></span></code></pre></div><p>阶段排序原则同步调整为：</p><ol><li>先校准事实源，避免旧模块命名继续误导后续生成</li><li>先收敛 <code>common</code>，稳定公共契约</li><li>再收敛 infra 主链路：<code>kv -&gt; realtime -&gt; security/web -&gt; gateway</code></li><li>infra 稳定后再进入 platform 主链路：<code>rbac -&gt; system -&gt; auth</code></li><li>最后处理 <code>admin-app</code> 装配层</li><li>非主链路平台模块进入按需标准化，不阻塞主链路</li></ol><hr><h2 id="_5-子阶段路线图" tabindex="-1">5. 子阶段路线图 <a class="header-anchor" href="#_5-子阶段路线图" aria-label="Permalink to &quot;5. 子阶段路线图&quot;">​</a></h2><h3 id="phase-1-模块归属决策门" tabindex="-1">Phase -1：模块归属决策门 <a class="header-anchor" href="#phase-1-模块归属决策门" aria-label="Permalink to &quot;Phase -1：模块归属决策门&quot;">​</a></h3><p>文档：<code>mango-docs/plans/2026-04-17-backend-module-by-module-refactor-plan.md</code></p><p>状态：已作为模块级计划前置决策写入</p><p>目标：</p><ul><li>固定身份事实、<code>mango-common</code> 准入边界、infra 能力域、platform 合并策略等关键决策</li><li>防止后续 Phase 在基础归属问题上反复返工</li></ul><h3 id="phase-0-事实源校准" tabindex="-1">Phase 0：事实源校准 <a class="header-anchor" href="#phase-0-事实源校准" aria-label="Permalink to &quot;Phase 0：事实源校准&quot;">​</a></h3><p>文档：<code>mango-docs/plans/2026-04-17-phase-0-fact-source-delivery-record.md</code></p><p>状态：已完成</p><p>目标：</p><ul><li>清理当前有效源码、POM、README、索引、架构文档中的旧模块事实源</li><li>明确历史 Sprint 文档允许保留旧名，但不得作为当前事实源</li></ul><h3 id="phase-1-mango-common" tabindex="-1">Phase 1：<code>mango-common</code> <a class="header-anchor" href="#phase-1-mango-common" aria-label="Permalink to &quot;Phase 1：`mango-common`&quot;">​</a></h3><p>文档：</p><ul><li><code>mango-docs/plans/2026-04-17-phase-1-common-class-ownership.md</code></li><li><code>mango-docs/plans/2026-04-17-phase-1-common-delivery-record.md</code></li></ul><p>状态：已完成</p><p>目标：</p><ul><li>将 <code>mango-common</code> 收敛为公共内核与公共契约</li><li>清理技术工具类、历史兼容类和领域色彩类型的错误归属</li><li>冻结 <code>common</code> 准入规则</li></ul><h3 id="phase-2-mango-infra-kv" tabindex="-1">Phase 2：<code>mango-infra-kv</code> <a class="header-anchor" href="#phase-2-mango-infra-kv" aria-label="Permalink to &quot;Phase 2：`mango-infra-kv`&quot;">​</a></h3><p>文档：</p><ul><li><code>mango-docs/plans/2026-04-17-phase-2-kv-configuration-rules.md</code></li><li><code>mango-docs/plans/2026-04-17-phase-2-kv-delivery-record.md</code></li></ul><p>状态：已完成</p><p>目标：</p><ul><li>收口 KV 配置命名、store 选择、use case bean 装配规则</li><li>明确 memory / redis / jdbc 实现选择口径</li><li>为后续 infra 模块提供稳定横切状态能力</li></ul><h3 id="phase-3-mango-infra-realtime" tabindex="-1">Phase 3：<code>mango-infra-realtime</code> <a class="header-anchor" href="#phase-3-mango-infra-realtime" aria-label="Permalink to &quot;Phase 3：`mango-infra-realtime`&quot;">​</a></h3><p>文档：</p><ul><li><code>mango-docs/plans/2026-04-18-infra-realtime-design.md</code></li><li><code>mango-docs/plans/2026-04-18-phase-3-messaging-delivery-record.md</code></li></ul><p>状态：已完成</p><p>目标：</p><ul><li>新建 <code>mango-infra-realtime</code> 聚合模块，拆分为 <code>api</code>、<code>core</code>、<code>starter</code>、<code>starter-remote</code></li><li>将旧 <code>mango-infra-sse</code> 与 <code>mango-infra-websocket</code> 合并为统一 server-client realtime 能力</li><li>提供 SSE、WebSocket、HTTP Polling、transport 协商、远程发布和 WebSocket 入站分发</li><li>将 <code>mango-biz-notification</code> 改为依赖 <code>mango-infra-realtime-api</code> 完成在线实时投递</li><li>将 <code>mango-admin-app</code> 的 WebSocket 运行时能力收敛到 <code>mango-infra-realtime-starter</code></li></ul><p>本阶段补充说明：</p><ul><li>这是对旧路线中阶段 3 偏离原计划后的正式校准。</li><li><code>mango-infra-realtime</code> 应位于 <code>mango-infra-kv</code> 之后、<code>mango-infra-security/web</code> 之前。</li><li>原因是 realtime 当前仍有轻量 header/query 读取，后续需要在 Phase 4/5 通过统一请求上下文、安全上下文和 gateway 可信 header 规则做被动适配。</li><li><code>mango-infra-realtime</code> 不承担业务通知、消息中心、离线消息、已读未读、MQ/Event、Agent 聚合、短信、邮件等业务或事件总线职责。</li><li>业务通知域继续由 <code>mango-biz-notification</code> 承担；未来 MQ/Event 能力如需要，另行规划 <code>mango-infra-messaging</code>。</li></ul><h3 id="phase-4-mango-infra-security-mango-infra-web" tabindex="-1">Phase 4：<code>mango-infra-security</code> + <code>mango-infra-web</code> <a class="header-anchor" href="#phase-4-mango-infra-security-mango-infra-web" aria-label="Permalink to &quot;Phase 4：`mango-infra-security` + `mango-infra-web`&quot;">​</a></h3><p>主文档：<code>mango-docs/plans/2026-04-17-backend-module-by-module-refactor-plan.md</code></p><p>状态：已完成，待人工验收</p><p>目标：</p><ul><li>去除 infra 对平台业务模型的反向依赖</li><li>冻结统一请求上下文 / 安全上下文契约</li><li>明确 userId、tenantId、认证状态、requestId、traceId、clientIp 的来源和读取方式</li><li>让 <code>mango-infra-realtime</code>、notification、audit、业务模块后续只通过 resolver/provider 被动消费统一上下文</li></ul><h3 id="phase-5-mango-gateway" tabindex="-1">Phase 5：<code>mango-gateway</code> <a class="header-anchor" href="#phase-5-mango-gateway" aria-label="Permalink to &quot;Phase 5：`mango-gateway`&quot;">​</a></h3><p>主文档：<code>mango-docs/plans/2026-04-17-backend-module-by-module-refactor-plan.md</code></p><p>状态：待执行</p><p>目标：</p><ul><li>清理 gateway 默认配置中的旧 <code>user/permission</code> 命名</li><li>冻结匿名路径、登录必需路径、内部路径的来源接口</li><li>明确 gateway 对认证结果治理、可信 header 注入、外部伪造 header 清洗的责任边界</li><li>明确 WebSocket/SSE/Polling 等长连接入口的路由、超时、限流、CORS/Origin 接入约定</li></ul><h3 id="phase-6-mango-authorization" tabindex="-1">Phase 6：<code>mango-authorization</code> <a class="header-anchor" href="#phase-6-mango-authorization" aria-label="Permalink to &quot;Phase 6：`mango-authorization`&quot;">​</a></h3><p>主文档：<code>mango-docs/plans/2026-04-17-backend-module-by-module-refactor-plan.md</code></p><p>状态：待执行</p><p>目标：</p><ul><li>将 <code>mango-authorization</code> 收敛为授权与访问控制中心</li><li>冻结 <code>authorization -&gt; auth</code> 的认证用户 / 权限桥接契约</li><li>收口用户事实、角色、菜单、按钮权限、公共路径的边界</li></ul><h3 id="phase-7-mango-system" tabindex="-1">Phase 7：<code>mango-system</code> <a class="header-anchor" href="#phase-7-mango-system" aria-label="Permalink to &quot;Phase 7：`mango-system`&quot;">​</a></h3><p>主文档：<code>mango-docs/plans/2026-04-17-backend-module-by-module-refactor-plan.md</code></p><p>状态：待执行</p><p>目标：</p><ul><li>将 <code>mango-system</code> 从系统杂项箱收敛为可维护的系统域集合</li><li>按 <code>dict/config/tenant/audit/route</code> 明确子域边界</li><li>输出未来物理拆分触发条件</li></ul><h3 id="phase-8-mango-auth" tabindex="-1">Phase 8：<code>mango-auth</code> <a class="header-anchor" href="#phase-8-mango-auth" aria-label="Permalink to &quot;Phase 8：`mango-auth`&quot;">​</a></h3><p>主文档：<code>mango-docs/plans/2026-04-17-backend-module-by-module-refactor-plan.md</code></p><p>状态：待执行</p><p>目标：</p><ul><li>将 <code>mango-auth</code> 收敛为认证域</li><li>保留登录、登出、refresh token、token validate 等认证职责</li><li>迁出或隔离防重放、幂等、验证码拦截、Web MVC 拦截治理等非认证职责</li></ul><h3 id="phase-9-mango-admin-app" tabindex="-1">Phase 9：<code>mango-admin-app</code> <a class="header-anchor" href="#phase-9-mango-admin-app" aria-label="Permalink to &quot;Phase 9：`mango-admin-app`&quot;">​</a></h3><p>主文档：<code>mango-docs/plans/2026-04-17-backend-module-by-module-refactor-plan.md</code></p><p>状态：待执行</p><p>目标：</p><ul><li>将 <code>mango-admin-app</code> 收敛为纯部署装配层</li><li>明确 local / remote starter 选择方式</li><li>输出 remote starter 覆盖清单与缺口清单</li></ul><h3 id="phase-10-平台非主链路模块标准化" tabindex="-1">Phase 10：平台非主链路模块标准化 <a class="header-anchor" href="#phase-10-平台非主链路模块标准化" aria-label="Permalink to &quot;Phase 10：平台非主链路模块标准化&quot;">​</a></h3><p>主文档：<code>mango-docs/plans/2026-04-17-backend-module-by-module-refactor-plan.md</code></p><p>状态：按需触发，不作为主链路阻断项</p><p>候选模块：</p><ul><li><code>mango-org</code></li><li><code>mango-captcha</code></li><li><code>mango-area</code></li><li><code>mango-i18n</code></li><li><code>mango-biz-notification</code></li><li><code>mango-ai</code></li></ul><p>目标：</p><ul><li>只在业务需求、依赖风险、API/core/starter 边界不一致等条件触发时执行</li><li>不因代码少、目录多、命名不对称而合并模块</li><li><code>mango-biz-notification</code> 只作为业务通知域标准化，不与 <code>mango-infra-realtime</code> 合并</li></ul><h3 id="backlog-候选-持久化抽象层收敛" tabindex="-1">Backlog 候选：持久化抽象层收敛 <a class="header-anchor" href="#backlog-候选-持久化抽象层收敛" aria-label="Permalink to &quot;Backlog 候选：持久化抽象层收敛&quot;">​</a></h3><p>状态：待规划，当前不进入执行</p><p>目标：</p><ul><li>为 <code>core</code> 层提供稳定的持久化抽象端口</li><li>让业务模块默认依赖 Mango 自己的 CRUD / Page 能力，而不是直接绑定 <code>mybatis-plus</code></li><li>保留 <code>mybatis-plus</code>、<code>jpa</code> 等不同持久化实现的适配空间</li></ul><p>当前结论：</p><ul><li>这件事值得做</li><li>但现在只适合进入 Backlog，不适合立即做全仓重构</li><li>后续如启动，建议先做设计和单模块 POC，再决定是否推广到生成器和全仓模块</li></ul><p>建议切入范围：</p><ol><li>定义持久化抽象端口（Repository / Page / CRUD）</li><li>先仅提供 <code>mybatis-plus</code> 适配实现</li><li>选择简单模块做 POC（如 <code>Post</code>）</li><li>验证通过后再决定是否落入正式 Phase / Sprint</li></ol><hr><h2 id="_6-各阶段之间的依赖关系" tabindex="-1">6. 各阶段之间的依赖关系 <a class="header-anchor" href="#_6-各阶段之间的依赖关系" aria-label="Permalink to &quot;6. 各阶段之间的依赖关系&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Phase -1 -&gt; Phase 0 -&gt; Phase 1 -&gt; Phase 2 -&gt; Phase 3 -&gt; Phase 4 -&gt; Phase 5 -&gt; Phase 6 -&gt; Phase 7 -&gt; Phase 8 -&gt; Phase 9</span></span></code></pre></div><p>说明：</p><ul><li>Phase -1 / Phase 0 完成后，后续阶段有稳定模块事实源</li><li>Phase 1 完成后，后续模块有稳定公共依赖基础</li><li>Phase 2 完成后，KV 横切状态能力的配置和装配规则稳定</li><li>Phase 3 完成后，旧 SSE/WebSocket 已收敛为 <code>mango-infra-realtime</code>，平台模块统一通过 realtime API 做在线投递</li><li>Phase 4 完成后，Web/Security/Context 的统一上下文契约稳定，realtime 可从轻量 header/query 读取过渡到被动消费 resolver/provider</li><li>Phase 5 完成后，gateway 的认证结果治理、可信 header 注入、外部伪造 header 清洗和长连接入口接入规则稳定</li><li>Phase 6 完成后，RBAC 的授权、用户事实、公共路径和认证桥接契约稳定</li><li>Phase 7 完成后，system 子域边界稳定</li><li>Phase 8 完成后，auth 回归认证域</li><li>Phase 9 完成后，admin-app 完成装配层收口</li><li>Phase 10 按需触发，不阻塞主链路</li></ul><hr><h2 id="_7-总体验收口径" tabindex="-1">7. 总体验收口径 <a class="header-anchor" href="#_7-总体验收口径" aria-label="Permalink to &quot;7. 总体验收口径&quot;">​</a></h2><p>总文档本身不验收代码，验收口径体现在各子阶段 / Phase 中。</p><p>总文档完成的标志是：</p><ul><li>总目标明确</li><li>重构顺序明确</li><li>子阶段边界明确</li><li>每个 Phase 都能独立交付</li></ul>',135)])])}const g=e(n,[["render",d]]);export{h as __pageData,g as default};
